const buyer_persona    = $('Code in JavaScript1').first().json.buyer_persona;
const question_type    = $('Code in JavaScript1').first().json.question_type;
const gap_summary      = $('Code in JavaScript1').first().json.gap_summary;

// ── Build escalation classifier system prompt ─────────────────
const system_prompt = `You are a customer service routing assistant for BOLDR, a premium Singapore-based titanium watch brand.

Your job is to read a customer email and classify exactly what type of escalation it is so it can be routed to the right team.

Return ONLY a valid JSON object with exactly these fields:
- "escalation_type": one of [corporate, service, media, angry, refund, unknown]
- "escalation_reason": one sentence explaining clearly why this needs escalation
- "route_to": one of [corporate@boldr.co, service@boldr.co, marketing@boldr.co, cs@boldr.co, admin.shopify.com]
- "urgency": one of [high, medium, low]

ESCALATION TYPE DEFINITIONS:
- corporate: customer is asking about bulk or corporate orders (more than 5 units), B2B pricing, or gifting at scale
- service: customer is asking about watch servicing, battery replacement, regulation, repairs, warranty claims, or damage to their watch
- media: customer identifies themselves as press, media, blogger, influencer, or is requesting a product for review
- angry: customer is expressing strong frustration, threatening a chargeback, disputing a charge, or mentioning legal action
- refund: customer is following up on an order cancellation, return, or refund — requires order lookup
- unknown: agent could not find the answer in the knowledge base and needs team lead assistance or customer wants to change or cancel engraving text and it has been more than 1 hour since the order was placed

ROUTING RULES — route_to must match exactly:
- corporate@boldr.co → escalation_type is corporate (bulk orders, B2B enquiries, more than 5 units)
- service@boldr.co   → escalation_type is service (servicing, warranty claims, repairs)
- marketing@boldr.co → escalation_type is media (press, influencer, media enquiries)
- cs@boldr.co        → escalation_type is angry or unknown (angry/chargeback, or answer not found in knowledge base)
- admin.shopify.com  → escalation_type is refund (order lookups, cancellations, refund status)

URGENCY RULES:
- high:   angry customer, chargeback threat, legal mention, or significant product defect
- medium: corporate enquiry, service/warranty claim, refund follow-up
- low:    media enquiry, unknown question needing team lead check

CRITICAL RULES:
- Choose exactly ONE escalation_type — pick the most dominant reason if multiple apply
- route_to must follow the routing rules above exactly
- Return ONLY a valid JSON object. No markdown, no explanation, no code fences.`;

// ── Build user prompt ─────────────────────────────────────────
const user_prompt = `Customer name: ${customer_name}
Customer email: ${customer_email}
Subject: ${subject}
Buyer persona (already classified): ${buyer_persona}
Question type (already classified): ${question_type}

Email body:
${message_body}

First AI draft reply (if any):
${draft_reply || 'No draft reply — question was not answerable from knowledge base.'}`;

// ── Return everything forward ─────────────────────────────────
return [{
  json: {
    system_prompt,
    user_prompt,
    customer_name,
    customer_email,
    subject,
    message_body,
    date_received,
    channel,
    draft_reply,
    answered_by_kb,
    buyer_persona,
    question_type,
    gap_summary,
  }
}];

// ── Parse escalation Qwen response ───────────────────────────
const raw = $input.first().json.choices[0].message.content;

let parsed;
try {
  parsed = JSON.parse(raw);
} catch(e) {
  parsed = {
    escalation_type:   'corporate',
    escalation_reason: 'Could not parse escalation response — manual review needed',
    route_to:          'cs@boldr.co',
    urgency:           'medium'
  };
}

// ── Carry all original fields forward ────────────────────────
return [{
  json: {
    // escalation fields from this Qwen call
    escalation_type:   parsed.escalation_type   ?? 'corporate',
    escalation_reason: parsed.escalation_reason ?? 'Unknown reason',
    route_to:          parsed.route_to          ?? 'cs@boldr.co',
    urgency:           parsed.urgency           ?? 'medium',

    // original fields from Code in JavaScript1
    customer_name:   $('Code in JavaScript1').first().json.customer_name,
    customer_email:  $('Code in JavaScript1').first().json.customer_email,
    subject:         $('Code in JavaScript1').first().json.subject,
    message_body:    $('Code in JavaScript1').first().json.message_body,
    date_received:   $('Code in JavaScript1').first().json.date_received,
    channel:         $('Code in JavaScript1').first().json.channel,
    draft_reply:     $('Code in JavaScript1').first().json.draft_reply,
    answered_by_kb:  $('Code in JavaScript1').first().json.answered_by_kb,
    buyer_persona:   $('Code in JavaScript1').first().json.buyer_persona,
    question_type:   $('Code in JavaScript1').first().json.question_type,
    gap_summary:     $('Code in JavaScript1').first().json.gap_summary,
  }
}];

